package day5;

/**
 * 
 */
public class Program5_BreakWhile {

	/**
	 * @param args
	 */
	public static void main(String[] args) {
		// TODO Auto-generated method stub
		 System.out.println("Hello");
		 int i=1;
		    while(i<=10) {
		    	if(i == 5) {
		    		break;
		    	}
		    	System.out.print(i+" ");
		    	
		    	i++;
		    	
		    	
		    }
		    System.out.println("\nBye");
	}

}
